create or replace function public.create_supplier(p_organization_id uuid,p_branch_id uuid,p_name text,p_email text,p_phone text,p_tin text,p_payment_terms_days integer,p_credit_limit numeric,p_bank_details text,p_actor_id uuid) returns jsonb language plpgsql security definer set search_path='' as $$ declare v_id uuid; begin if p_actor_id is distinct from auth.uid() then raise exception 'Actor mismatch'; end if; if not public.has_org_role(p_organization_id,array['owner','admin','accountant','inventory']::public.app_role[]) then raise exception 'Insufficient purchasing permission'; end if; if nullif(trim(p_name),'') is null then raise exception 'Supplier name is required'; end if; insert into public.suppliers(organization_id,branch_id,name,email,phone,tin,payment_terms_days,credit_limit,bank_details,created_by) values(p_organization_id,p_branch_id,trim(p_name),nullif(trim(p_email),''),nullif(trim(p_phone),''),nullif(trim(p_tin),''),greatest(coalesce(p_payment_terms_days,0),0),greatest(coalesce(p_credit_limit,0),0),nullif(trim(p_bank_details),''),p_actor_id) returning id into v_id; insert into public.audit_events(organization_id,actor_id,action,entity_type,entity_id,metadata) values(p_organization_id,p_actor_id,'purchasing.supplier.created','supplier',v_id,jsonb_build_object('name',trim(p_name))); return jsonb_build_object('id',v_id,'number',trim(p_name)); end $$;

create or replace function public.create_purchase_request(p_organization_id uuid,p_branch_id uuid,p_request_date date,p_needed_by date,p_department text,p_requested_by_name text,p_notes text,p_lines jsonb,p_actor_id uuid) returns jsonb language plpgsql security definer set search_path='' as $$ declare v_id uuid; v_no text; line jsonb; v_product uuid; v_warehouse uuid; v_description text; v_qty numeric; v_cost numeric; begin if p_actor_id is distinct from auth.uid() then raise exception 'Actor mismatch'; end if; if not public.has_org_role(p_organization_id,array['owner','admin','accountant','inventory','manager','staff']::public.app_role[]) then raise exception 'Insufficient purchasing permission'; end if; if jsonb_typeof(p_lines)<>'array' or jsonb_array_length(p_lines)=0 or jsonb_array_length(p_lines)>100 then raise exception 'Request requires 1 to 100 lines'; end if; v_no:=public.next_document_number(p_organization_id,'PR'); insert into public.purchase_requests(organization_id,branch_id,request_number,request_date,needed_by,department,requested_by_name,status,notes,created_by) values(p_organization_id,p_branch_id,v_no,coalesce(p_request_date,current_date),p_needed_by,nullif(trim(p_department),''),nullif(trim(p_requested_by_name),''),'submitted',nullif(trim(p_notes),''),p_actor_id) returning id into v_id; for line in select value from jsonb_array_elements(p_lines) loop v_product:=nullif(line->>'productId','')::uuid; v_warehouse:=nullif(line->>'warehouseId','')::uuid; v_description:=nullif(trim(line->>'description'),''); v_qty:=coalesce((line->>'quantity')::numeric,0); v_cost:=coalesce((line->>'estimatedUnitCost')::numeric,0); if v_product is not null then select name into v_description from public.products where id=v_product and organization_id=p_organization_id and is_active; if not found then raise exception 'Product not found'; end if; end if; if v_description is null or v_qty<=0 or v_cost<0 then raise exception 'Invalid request line'; end if; if v_warehouse is not null and not exists(select 1 from public.warehouses where id=v_warehouse and organization_id=p_organization_id and is_active) then raise exception 'Warehouse not found'; end if; insert into public.purchase_request_items(organization_id,purchase_request_id,product_id,description,quantity,estimated_unit_cost,warehouse_id) values(p_organization_id,v_id,v_product,v_description,v_qty,v_cost,v_warehouse); end loop; insert into public.audit_events(organization_id,actor_id,action,entity_type,entity_id,metadata) values(p_organization_id,p_actor_id,'purchasing.request.submitted','purchase_request',v_id,jsonb_build_object('number',v_no)); return jsonb_build_object('id',v_id,'number',v_no); end $$;

create or replace function public.set_purchase_request_status(p_organization_id uuid,p_request_id uuid,p_status text,p_actor_id uuid) returns jsonb language plpgsql security definer set search_path='' as $$ declare r public.purchase_requests%rowtype; begin if p_actor_id is distinct from auth.uid() then raise exception 'Actor mismatch'; end if; if not public.has_org_role(p_organization_id,array['owner','admin','accountant','manager']::public.app_role[]) then raise exception 'Insufficient approval permission'; end if; if p_status not in ('approved','rejected','cancelled') then raise exception 'Invalid request status'; end if; select * into r from public.purchase_requests where id=p_request_id and organization_id=p_organization_id for update; if not found then raise exception 'Purchase request not found'; end if; if r.status not in ('submitted','approved') then raise exception 'Request cannot be updated from current status'; end if; update public.purchase_requests set status=p_status,approved_by=case when p_status='approved' then p_actor_id else approved_by end,approved_at=case when p_status='approved' then now() else approved_at end,updated_at=now() where id=p_request_id; insert into public.audit_events(organization_id,actor_id,action,entity_type,entity_id,metadata) values(p_organization_id,p_actor_id,'purchasing.request.'||p_status,'purchase_request',p_request_id,jsonb_build_object('number',r.request_number)); return jsonb_build_object('id',p_request_id,'number',r.request_number,'status',p_status); end $$;

revoke all on function public.create_supplier(uuid,uuid,text,text,text,text,integer,numeric,text,uuid) from public; grant execute on function public.create_supplier(uuid,uuid,text,text,text,text,integer,numeric,text,uuid) to authenticated;
revoke all on function public.create_purchase_request(uuid,uuid,date,date,text,text,text,jsonb,uuid) from public; grant execute on function public.create_purchase_request(uuid,uuid,date,date,text,text,text,jsonb,uuid) to authenticated;
revoke all on function public.set_purchase_request_status(uuid,uuid,text,uuid) from public; grant execute on function public.set_purchase_request_status(uuid,uuid,text,uuid) to authenticated;